from __future__ import annotations

import os
import shutil
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import Literal

_HOME = Path.home()

Action = Literal["created", "updated", "unchanged", "not-found", "removed", "error", "skipped"]
Mode = Literal["install", "uninstall"]

AGNTSPCE_SEARCH_START = "<!-- AGNTSPCE_SEARCH_START -->"
AGNTSPCE_SEARCH_END = "<!-- AGNTSPCE_SEARCH_END -->"


@dataclass(frozen=True)
class WriteResult:
    path: Path
    action: Action


@dataclass(frozen=True)
class AgentTarget:
    id: str
    display_name: str
    binary: str | None
    config_dir: Path | None
    mcp_config_path: Path | None
    mcp_section_key: str
    instructions_path: Path | None


AGENTS: list[AgentTarget] = [
    AgentTarget(
        id="claude",
        display_name="Claude Code",
        binary="claude",
        config_dir=_HOME / ".claude",
        mcp_config_path=_HOME / ".claude.json",
        mcp_section_key="mcpServers",
        instructions_path=_HOME / ".claude" / "CLAUDE.md",
    ),
    AgentTarget(
        id="opencode",
        display_name="Opencode",
        binary="opencode",
        config_dir=_HOME / ".config" / "opencode",
        mcp_config_path=_HOME / ".config" / "opencode" / "opencode.jsonc",
        mcp_section_key="mcp",
        instructions_path=_HOME / ".config" / "opencode" / "AGENTS.md",
    ),
]


def is_detected(agent: AgentTarget) -> bool:
    if agent.binary and shutil.which(agent.binary):
        return True
    return bool(agent.config_dir and agent.config_dir.exists())
